# 步骤1: 检查并停止卡住的旧进程
Write-Host "=== 步骤1: 检查并停止旧进程 ===" -ForegroundColor Green
$procs = @('winget', 'curl', 'python', 'py311', 'python-3.11.9-amd64')
foreach ($p in $procs) {
    $found = Get-Process -Name $p -ErrorAction SilentlyContinue
    if ($found) {
        Write-Host "停止进程: $p (PID: $($found.Id))"
        Stop-Process -Name $p -Force -ErrorAction SilentlyContinue
    }
}
Write-Host "旧进程检查完成" -ForegroundColor Green

# 步骤3: 将安装包从WSL复制到Windows Temp目录
Write-Host "`n=== 步骤3: 复制安装包到Windows ===" -ForegroundColor Green
$WslExePath = "/home/yirongbest/py311.exe"
$WinTempPath = "C:\Users\yuyirong\AppData\Local\Temp\py311.exe"

# 确保目标目录存在
$TempDir = "C:\Users\yuyirong\AppData\Local\Temp"
if (!(Test-Path $TempDir)) {
    New-Item -ItemType Directory -Path $TempDir -Force | Out-Null
}

# 从WSL复制到Windows
Write-Host "复制 $WslExePath 到 $WinTempPath..."
wsl -e cp "$WslExePath" "/mnt/c/Users/yuyirong/AppData/Local/Temp/py311.exe"

# 验证复制结果
if (Test-Path $WinTempPath) {
    $Size = (Get-Item $WinTempPath).Length
    Write-Host "复制成功: $WinTempPath, 大小: $Size bytes" -ForegroundColor Green
    if ($Size -gt 20971520) {
        Write-Host "文件大小验证通过" -ForegroundColor Green
    } else {
        Write-Host "错误: 文件大小不足" -ForegroundColor Red
        exit 1
    }
} else {
    Write-Host "错误: 复制失败，文件不存在" -ForegroundColor Red
    exit 1
}
Write-Host "步骤3完成" -ForegroundColor Green

# 步骤4: 静默安装Python 3.11
Write-Host "`n=== 步骤4: 静默安装Python 3.11 ===" -ForegroundColor Green
$InstallerPath = "C:\Users\yuyirong\AppData\Local\Temp\py311.exe"

# 检查是否已安装Python 3.11
$PythonPath = "C:\Users\yuyirong\AppData\Local\Programs\Python\Python311\python.exe"
if (Test-Path $PythonPath) {
    Write-Host "Python 3.11 已安装，跳过安装步骤" -ForegroundColor Yellow
    & $PythonPath --version
} else {
    Write-Host "开始静默安装 Python 3.11..." -ForegroundColor Green
    Write-Host "安装参数: /quiet InstallAllUsers=0 PrependPath=1 Include_test=0"

    # 执行静默安装
    $Process = Start-Process -FilePath $InstallerPath -ArgumentList "/quiet", "InstallAllUsers=0", "PrependPath=1", "Include_test=0" -Wait -PassThru

    if ($Process.ExitCode -eq 0) {
        Write-Host "Python 3.11 安装成功" -ForegroundColor Green
    } else {
        Write-Host "安装失败，退出码: $($Process.ExitCode)" -ForegroundColor Red
        exit 1
    }
}

# 验证安装
Write-Host "`n验证Python安装:" -ForegroundColor Green
& $PythonPath --version
& $PythonPath -c "import sys; print(f'Python executable: {sys.executable}')"
Write-Host "步骤4完成" -ForegroundColor Green

